import pandas as pd

def read_csv_file(file_name):
    data = pd.read_csv(file_name)
    print(data)

import ast

def _parse_arg(raw):
    try:
        return ast.literal_eval(raw)
    except Exception:
        return raw

_inputs = []
try:
    while True:
        _inputs.append(input())
except EOFError:
    pass
file_name = _parse_arg(_inputs[0]) if len(_inputs) > 0 else ""

print(read_csv_file(file_name))
